	rpcFns["GetMonitorEvents"] = ccl.doRPCGetMonitorEvents
	rpcFns["GetMonitorHistory"] = ccl.doRPCGetMonitorHistory
	rpcFns["GetRecordTypeSummary"] = ccl.doRPCGetRecordTypeSummary
	rpcFns["GetSourceSummary"] = ccl.doRPCGetSourceSummary
